for (const item of $input.all()) {
  for (const key of Object.keys(item.binary || {})) {
    const bin = item.binary[key];
    const name = (bin.fileName || '').toLowerCase();
    if (bin.mimeType === 'application/octet-stream') {
      if (name.endsWith('.pdf')) bin.mimeType = 'application/pdf';
      else bin.mimeType = 'text/plain';
    }
  }
}
return $input.all();

const text = $input.first().json.data;
// Read KB from the form trigger node directly (not current input)
const kb = $('Subir Archivo').first().json['Base de Conocimiento'] || 'hansbiomed_knowledge';
const chunkSize = 1000;
const overlap = 200;
const chunks = [];
let pos = 0;
while (pos < text.length) {
  const end = Math.min(pos + chunkSize, text.length);
  chunks.push({ content: text.slice(pos, end), kb_table: kb });
  pos += chunkSize - overlap;
  if (end === text.length) break;
}
return chunks;
